INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1000001, 2, -416.5, "2025/01/31 12:00:00", 190801, "2030/01/01 14:59:59", 1, 0.0, 62, 3.414, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 1, "ミッションをクリアして、\n報酬をゲットしましょう！", 1000002, 2, -416.5, "2025/01/31 12:00:00", 190801, "2030/01/01 14:59:59", 2, 0.0, 62, 3.099, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 1, "受け取ることができる\n報酬があるようです\n確認してみてください", 1000003, 2, -416.5, "2025/01/31 12:00:00", 190801, "2030/01/01 14:59:59", 3, 0.0, 63, 2.801, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 1, "報酬がもらえますよ！\nチェックしてみてください", 1000004, 2, -416.5, "2025/01/31 12:00:00", 190801, "2030/01/01 14:59:59", 4, 0.0, 63, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1000005, 1, -363.0, "2025/01/31 12:00:00", 190801, "2030/01/01 14:59:59", 5, 0.0, 64, 2.12, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 1, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1000006, 2, -363.0, "2025/01/31 12:00:00", 190801, "2030/01/01 14:59:59", 6, 0.0, 64, 1.68, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1000007, 1, -363.0, "2025/01/31 12:00:00", 190801, "2030/01/01 14:59:59", 7, 0.0, 64, 2.33, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, 10201, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 1020101, 7, -285.0, "2025/01/31 12:00:00", 133701, "2030/01/01 14:59:59", 101, -6.0, 61, 5.18, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10201, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 1020102, 2, -285.0, "2025/01/31 12:00:00", 133901, "2030/01/01 14:59:59", 201, -2.0, 61, 8.77, "クリスティーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, 10201, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 1020103, 1, -285.0, "2025/01/31 12:00:00", 133801, "2030/01/01 14:59:59", 301, 0.0, 61, 15.5, "ネネカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 10202, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 1020201, 5, -285.0, "2025/02/28 12:00:00", 134301, "2030/01/01 14:59:59", 101, 0.0, 61, 9.061, "ランファ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10202, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 1020202, 2, -285.0, "2025/02/28 12:00:00", 134401, "2030/01/01 14:59:59", 201, 0.0, 61, 7.699, "チカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10203, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 1020301, 2, -285.0, "2025/03/31 12:00:00", 134601, "2030/01/01 14:59:59", 101, 0.0, 61, 8.595, "アオイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10203, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 1020302, 2, -285.0, "2025/03/31 12:00:00", 134501, "2030/01/01 14:59:59", 201, 0.0, 61, 7.758, "クローチェ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 10204, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 1020401, 6, -285.0, "2025/04/30 12:00:00", 132302, "2030/01/01 14:59:59", 101, 0.0, 61, 7.0, "ルイズマリー");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10204, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 1020402, 2, -285.0, "2025/04/30 12:00:00", 132402, "2030/01/01 14:59:59", 201, 0.0, 61, 7.904, "イロハ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10204, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 1020403, 2, -285.0, "2025/04/30 12:00:00", 132502, "2030/01/01 14:59:59", 301, 0.0, 61, 8.487, "ソノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10205, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 1020502, 2, -285.0, "2025/05/31 12:00:00", 134901, "2030/01/01 14:59:59", 101, 0.0, 61, 8.763, "カノン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10205, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 1020503, 3, -285.0, "2025/05/31 12:00:00", 134801, "2030/01/01 14:59:59", 201, 0.0, 61, 6.417, "ツムギ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, 10206, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 1020601, 7, -285.0, "2025/06/30 12:00:00", 135001, "2030/01/01 14:59:59", 101, 0.0, 61, 10.335, "エリス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 10206, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 1020602, 4, -285.0, "2025/06/30 12:00:00", 135101, "2030/01/01 14:59:59", 201, 0.0, 61, 6.281, "シェフィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10206, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 1020603, 2, -285.0, "2025/06/30 12:00:00", 135201, "2030/01/01 14:59:59", 301, 0.0, 61, 12.244, "プレシア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 10207, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 1020701, 8, -285.0, "2025/07/31 12:00:00", 135301, "2030/01/01 14:59:59", 101, 0.0, 61, 6.339, "クリア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7, 10207, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 1020702, 9, -285.0, "2025/07/31 12:00:00", 135401, "2030/01/01 14:59:59", 201, 0.0, 61, 8.184, "アネモネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9, 10208, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 1020801, 2, -285.0, "2025/08/31 12:00:00", 129101, "2030/01/01 14:59:59", 101, 0.0, 61, 3.906, "アイラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10208, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 1020802, 2, -285.0, "2025/08/31 12:00:00", 129201, "2030/01/01 14:59:59", 201, 0.0, 61, 14.465, "シナツ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10208, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 1020803, 3, -285.0, "2025/08/31 12:00:00", 100101, "2030/01/01 14:59:59", 301, 0.0, 61, 8.662, "ヒヨリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10208, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 1020804, 3, -285.0, "2025/08/31 12:00:00", 100301, "2030/01/01 14:59:59", 401, 0.0, 61, 10.915, "レイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10209, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 1020901, 7, -285.0, "2025/09/30 12:00:00", 135802, "2030/01/01 14:59:59", 101, 0.0, 61, 6.042, "ユキノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10209, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 1020902, 1, -285.0, "2025/09/30 12:00:00", 135903, "2030/01/01 14:59:59", 201, 0.0, 61, 9.402, "サツキ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8, 10209, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 1020903, 1, -285.0, "2025/09/30 12:00:00", 136902, "2030/01/01 14:59:59", 301, 0.0, 61, 8.16, "ルルィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, 10210, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 1021001, 2, -285.0, "2025/10/31 12:00:00", 137401, "2030/01/01 14:59:59", 101, 0.0, 61, 5.0, "カスミ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10210, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 1021002, 1, -285.0, "2025/10/31 12:00:00", 136001, "2030/01/01 14:59:59", 201, 0.0, 61, 8.12, "アラクネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10210, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 1021003, 2, -285.0, "2025/10/31 12:00:00", 136202, "2030/01/01 14:59:59", 301, 0.0, 61, 6.386, "ナーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, 10211, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 1021101, 4, -285.0, "2025/11/30 12:00:00", 136402, "2030/01/01 14:59:59", 101, 0.0, 61, 7.438, "ユイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10211, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 1021102, 5, -285.0, "2025/11/30 12:00:00", 136302, "2030/01/01 14:59:59", 201, 0.0, 61, 8.35, "ミソラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10212, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 1021201, 2, -285.0, "2025/12/31 12:00:00", 136501, "2030/01/01 14:59:59", 101, 0.0, 61, 5.0, "シズル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10212, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 1021202, 2, -285.0, "2025/12/31 12:00:00", 137902, "2030/01/01 14:59:59", 201, 0.0, 61, 5.25, "リノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10212, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 1021203, 2, -285.0, "2025/12/31 12:00:00", 106801, "2030/01/01 14:59:59", 301, 0.0, 61, 7.5, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10213, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 1021301, 2, -285.0, "2026/01/31 12:00:00", 126501, "2030/01/01 14:59:59", 101, 0.0, 61, 8.204, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10213, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 1021302, 2, -285.0, "2026/01/31 12:00:00", 129701, "2030/01/01 14:59:59", 201, 0.0, 61, 7.176, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10213, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 1021303, 5, -285.0, "2026/01/31 12:00:00", 133101, "2030/01/01 14:59:59", 301, 0.0, 61, 8.602, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10213, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 1021304, 3, -285.0, "2026/02/06 12:00:00", 138101, "2030/01/01 14:59:59", 102, 0.0, 61, 10.14, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10213, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 1021305, 7, -285.0, "2026/02/06 12:00:00", 138201, "2030/01/01 14:59:59", 202, 0.0, 61, 10.152, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10213, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 1021306, 3, -285.0, "2026/02/06 12:00:00", 138001, "2030/01/01 14:59:59", 302, 0.0, 61, 9.688, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 10213, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 1021307, 1, -285.0, "2026/02/12 12:00:00", 138301, "2030/01/01 14:59:59", 401, 0.0, 61, 5.928, "ペコリーヌ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10214, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 1021401, 2, -285.0, "2026/02/28 12:00:00", 138702, "2030/01/01 14:59:59", 101, 0.0, 61, 9.19, "ワカナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 10214, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 1021402, 3, -285.0, "2026/02/28 12:00:00", 138802, "2030/01/01 14:59:59", 201, 0.0, 61, 8.724, "シオリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 10215, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 1021501, 1, -285.0, "2026/03/31 12:00:00", 138902, "2030/01/01 14:59:59", 101, 0.0, 61, 7.758, "グレイス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, 10215, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 1021502, 4, -285.0, "2026/03/31 12:00:00", 139002, "2030/01/01 14:59:59", 201, 0.0, 61, 6.375, "キョウカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, 10215, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 1021503, 1, -285.0, "2026/03/31 12:00:00", 136902, "2030/01/01 14:59:59", 301, 0.0, 61, 6.173, "ルルィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 2000001, 2, -416.5, "2026/04/10 12:00:00", 190801, "2030/01/01 14:59:59", 1, 0.0, 62, 3.414, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", 2000002, 2, -416.5, "2026/04/10 12:00:00", 190801, "2030/01/01 14:59:59", 2, 0.0, 62, 3.099, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 2, "受け取ることができる\n報酬があるようです\n確認してみてください", 2000003, 2, -416.5, "2026/04/10 12:00:00", 190801, "2030/01/01 14:59:59", 3, 0.0, 63, 2.801, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 2, "報酬がもらえますよ！\nチェックしてみてください", 2000004, 2, -416.5, "2026/04/10 12:00:00", 190801, "2030/01/01 14:59:59", 4, 0.0, 63, 0.0, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 2, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2000005, 1, -363.0, "2026/04/10 12:00:00", 190801, "2030/01/01 14:59:59", 5, 0.0, 64, 2.12, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 2000006, 2, -363.0, "2026/04/10 12:00:00", 190801, "2030/01/01 14:59:59", 6, 0.0, 64, 1.68, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 2, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2000007, 1, -363.0, "2026/04/10 12:00:00", 190801, "2030/01/01 14:59:59", 7, 0.0, 64, 2.33, "カリン");
